import{_ as a,o as n,c as t,ag as s}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"🏗 PROJECT SPEC (Technical Architecture Specification) - VLTA AI 知识库","description":"","frontmatter":{},"headers":[],"relativePath":"docs/PROJECT_SPEC.md","filePath":"docs/PROJECT_SPEC.md"}'),o={name:"docs/PROJECT_SPEC.md"};function c(i,e,r,l,p,d){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="🏗-project-spec-technical-architecture-specification-vlta-ai-知识库" tabindex="-1">🏗 PROJECT SPEC (Technical Architecture Specification) - VLTA AI 知识库 <a class="header-anchor" href="#🏗-project-spec-technical-architecture-specification-vlta-ai-知识库" aria-label="Permalink to &quot;🏗 PROJECT SPEC (Technical Architecture Specification) - VLTA AI 知识库&quot;">​</a></h1><blockquote><p><strong>💡 Antigravity SPEC 定位声明</strong> 这是一个特殊的“开源知识库/论文集”项目。系统架构的核心诉求不在于全栈业务逻辑，而在于<strong>极速的响应、极致的阅读体验 (Vibe)、强大的目录索引与全局搜索能力，以及对中英双语 (i18n) 的完美支持</strong>。</p></blockquote><hr><h2 id="_1-🛠-核心技术栈-tech-stack-core-dependencies" tabindex="-1">1. 🛠 核心技术栈 (Tech Stack &amp; Core Dependencies) <a class="header-anchor" href="#_1-🛠-核心技术栈-tech-stack-core-dependencies" aria-label="Permalink to &quot;1. 🛠 核心技术栈 (Tech Stack &amp; Core Dependencies)&quot;">​</a></h2><ul><li><strong>核心框架 (Framework)</strong>: <strong>VitePress</strong> (基于 Vue 和 Vite 的静态站点生成器。相比 Docusaurus 更加轻量极速，拥有完美的 Markdown 语法拓展和开箱即用的极简暗黑风格)。</li><li><strong>包管理器 (Package Manager)</strong>: <code>npm</code> (针对文档型项目保持普适性，或遵循外层规约使用 <code>pnpm</code>)。</li><li><strong>搜索机制 (Search)</strong>: VitePress 内置的 Local Search (基于 MiniSearch)。</li><li><strong>多语言支持 (i18n)</strong>: VitePress 原生路由多语言映射（默认 <code>/</code> 为中文，<code>/en/</code> 为英文拓展目录）。</li><li><strong>部署策略 (Deployment)</strong>: 静态构建 (<code>npm run docs:build</code>) 后直接部署至 GitHub Pages 分支。</li></ul><h2 id="_2-🗺-架构拓扑树-architecture-topology" tabindex="-1">2. 🗺 架构拓扑树 (Architecture Topology) <a class="header-anchor" href="#_2-🗺-架构拓扑树-architecture-topology" aria-label="Permalink to &quot;2. 🗺 架构拓扑树 (Architecture Topology)&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VLTA_AI/</span></span>
<span class="line"><span>├── .vitepress/              # VitePress 全局配置与渲染层</span></span>
<span class="line"><span>│   └── config.mts           # 核心控制锚点：定义导航栏、侧边栏、语言、搜索规则</span></span>
<span class="line"><span>├── public/                  # 静态资源存放区 (图片、Logo 等)</span></span>
<span class="line"><span>├── index.md                 # 中文首页 (具有 Hero 沉浸式落地页)</span></span>
<span class="line"><span>├── en/                      # 英文区入口</span></span>
<span class="line"><span>│   └── index.md             </span></span>
<span class="line"><span>├── AI tools.md              # 知识文章实体</span></span>
<span class="line"><span>├── 20260308 AI General.md   # 知识文章实体</span></span>
<span class="line"><span>├── PRD.md                   # 架构文档实体 (纳入知识库渲染)</span></span>
<span class="line"><span>├── PROJECT_SPEC.md          # 架构文档实体 (纳入知识库渲染)</span></span>
<span class="line"><span>└── package.json             # 依赖与命令执行表</span></span></code></pre></div><h2 id="_3-📝-文档路由契约-content-routing-contract" tabindex="-1">3. 📝 文档路由契约 (Content &amp; Routing Contract) <a class="header-anchor" href="#_3-📝-文档路由契约-content-routing-contract" aria-label="Permalink to &quot;3. 📝 文档路由契约 (Content &amp; Routing Contract)&quot;">​</a></h2><ul><li><strong>物理即路由</strong>: 项目采用最扁平的物理路由策略。根目录下的任何 <code>[name].md</code> 都会自动渲染为 <code>/[name].html</code>。</li><li><strong>前置元数据 (Frontmatter)</strong>: 每篇被收录的顶级长篇论文/日记，应在第一行使用 YAML 标记其 <code>title</code>, <code>description</code>，以备搜索引擎收录。</li><li><strong>热更新录入</strong>: 任何新的学习产出（如分析 Manus 的新文件），只需丢入项目并更新 <code>.vitepress/config.mts</code> 的 <code>sidebar</code>，即可形成永久知识快照。</li></ul><h2 id="_4-🛡-架构级防篡改底线-documentation-redlines" tabindex="-1">4. 🛡 架构级防篡改底线 (Documentation Redlines) <a class="header-anchor" href="#_4-🛡-架构级防篡改底线-documentation-redlines" aria-label="Permalink to &quot;4. 🛡 架构级防篡改底线 (Documentation Redlines)&quot;">​</a></h2><ul><li><strong>非必要不挂载组件</strong>: 由于这是知识库，严禁在 Markdown 文件中大量手写 Vue/React 组件。尽量依赖纯 Markdown 语法和扩展标记（如 <code>::: info</code> 提示块），确保即使脱离 VitePress，内容依然可以在 GitHub 上完美裸读。</li><li><strong>死链防御</strong>: 重命名文件时，必须同步使用 <code>grep_search</code> 全局搜索并替换其他 <code>.md</code> 中的交叉引用链接，保持知识图谱的完整性。</li></ul><hr><h2 id="_5-🧠-决策轨迹挂载点-architecture-thought-log" tabindex="-1">5. 🧠 决策轨迹挂载点 (Architecture Thought Log) <a class="header-anchor" href="#_5-🧠-决策轨迹挂载点-architecture-thought-log" aria-label="Permalink to &quot;5. 🧠 决策轨迹挂载点 (Architecture Thought Log)&quot;">​</a></h2><ul><li><strong>[2026-03-22] [Decision]</strong>: 选择 <strong>VitePress</strong> 而非 Next.js / Docusaurus。 <ul><li><em>Context</em>: PRD 明确此项目是学习动态库、论文集，要求极高的响应速度和 Vibe 设计。</li><li><em>Trade-off</em>: 放弃了 Docusaurus 那种复杂的 React 插件生态，换取了极简、最高效的 Markdown 渲染闭环。不需要写代码，专注写内容。</li></ul></li></ul>`,14)])])}const g=a(o,[["render",c]]);export{u as __pageData,g as default};
